/**
 * Provides a utility function to determine whether a graphic's origin is a [KMLGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/KMLGraphicOrigin/).
 *
 * @since 5.0
 * @example
 * // Use hitTest() to get a graphic, then check whether it originated from a KMLLayer.
 * view.hitTest(screenPoint).then((response) => {
 *   const graphic = response.results[0]?.graphic;
 *   if (!graphic) {
 *     return;
 *   }
 *   if (isKMLGraphicOrigin(graphic.origin)) {
 *     // hitTest returned a graphic from a KMLLayer.
 *     // Use this info for your processing logic.
 *   } else {
 *     console.log("graphic's origin is NOT a KMLLayer");
 *   }
 * });
 */
import type GraphicOrigin from "./GraphicOrigin.js";
import type KMLGraphicOrigin from "./KMLGraphicOrigin.js";

/**
 * Utility function that determines whether a graphic’s origin is a [KMLGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/KMLGraphicOrigin/).
 *
 * @param origin - The graphic origin to check.
 * @returns Returns `true` if the graphic origin is of type [KMLGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/KMLGraphicOrigin/), `false` otherwise.
 */
export function isKMLGraphicOrigin(origin: GraphicOrigin | null | undefined): origin is KMLGraphicOrigin;